const math = require("mathjs");

const generate = (usePredefinedValues = 0) => {
    // 1. Dynamic Parameter Selection
    const unitSystems = {
        si: {
            speed: 'km/h',
            distance: 'm',
            time: 's'
        },
        uscs: {
            speed: 'mph',
            distance: 'ft',
            time: 's'
        }
    };

    const selectedSystem = math.randomInt(0, 2) === 0 ? 'si' : 'uscs';
    const units = unitSystems[selectedSystem];

    // 2. Value Generation
    let v, t;
    if (usePredefinedValues === 0) {
        v = math.randomInt(10, 31); // velocity between 10 and 30 units
        t = math.randomInt(1, 11); // time between 1 and 10 units
    } else {
        v = 20;
        t = 5;
    }

    // 3. Computation Logic
    let v_converted;
    if (units.speed === "km/h") {
        v_converted = v; // No conversion needed
    } else { // units.speed === "mph"
        v_converted = v * 1.46667; // convert mph to ft/s
    }

    const d = v_converted * t; // distance = speed * time

    // Return the structured data
    return {
        params: {
            v: v,
            t: t,
            unitsSpeed: units.speed,
            unitsTime: units.time,
            unitsDistance: units.distance
        },
        correct_answers: {
            d: math.round(d, 3) // Round to 3 decimal places
        },
        nDigits: 3,
        sigfigs: 3
    };
};

module.exports = { generate };

