import math
import random

def generate(use_predefined_values=0):
    # Define predefined values if requested
    predefined_data = [
        {'v': 30, 'unitsSpeed': 'm/s', 't': 10, 'unitsTime': 's'},
        {'v': 50, 'unitsSpeed': 'km/h', 't': 2, 'unitsTime': 'h'},
        {'v': 20, 'unitsSpeed': 'm/s', 't': 5, 'unitsTime': 's'},
        {'v': 60, 'unitsSpeed': 'km/h', 't': 1, 'unitsTime': 'h'},
        {'v': 45, 'unitsSpeed': 'm/s', 't': 3, 'unitsTime': 's'},
    ]

    # Select values based on the use_predefined_values flag
    try:
        if use_predefined_values == 1:
            params = predefined_data[random.randint(0, len(predefined_data) - 1)]
        else:
            # Generate random values
            if random.choice([True, False]):
                # Choose SI units
                params = {
                    'v': random.uniform(10, 100),  # speed in m/s
                    'unitsSpeed': 'm/s',
                    't': random.uniform(1, 60),  # time in seconds
                    'unitsTime': 's',
                }
            else:
                # Choose USCS units (use miles/hour)
                params = {
                    'v': random.uniform(10, 100),  # speed in miles/hour
                    'unitsSpeed': 'miles/hour',
                    't': random.uniform(1, 60),  # time in seconds
                    'unitsTime': 's',
                }

        # Convert USCS speed to m/s
        if params['unitsSpeed'] == 'miles/hour':
            params['v'] *= 0.44704  # conversion factor from miles/hour to m/s

        # Distance calculation: $d = v \cdot t$
        speed = params['v']  # speed in m/s
        time = params['t']  # time in s
        distance = speed * time  # distance in m

        # Returning structured results
        return {
            'params': {
                'v': round(speed, 3),
                'unitsSpeed': params['unitsSpeed'],
                't': round(time, 3),
                'unitsTime': params['unitsTime'],
                'd': round(distance, 3),
                'unitsDistance': 'meters',
            },
            'correct_answers': {
                'd': round(distance, 3),
            },
            'nDigits': 3,
            'sigfigs': 3,
        }
    except Exception as e:
        return {
            'error': str(e)
        }
